#!/bin/bash
set -e

echo "🧹 Cleaning up any legacy AgentFlow installation..."
rm -rf .agentflow .agents .claude/agents .claude/skills/fable-reasoning .claude/skills/domain-vocabulary Personas

echo "📦 Extracting AgentFlow System..."

PAYLOAD_FILE=$(mktemp)
# Extract payload from the end of this script
sed -e '1,/^__PAYLOAD_BELOW__/d' "$0" | base64 -d > "$PAYLOAD_FILE" 2>/dev/null || sed -e '1,/^__PAYLOAD_BELOW__/d' "$0" | base64 -D > "$PAYLOAD_FILE"

tar -xzf "$PAYLOAD_FILE"
rm "$PAYLOAD_FILE"

echo "📝 Scaffolding Tracking Templates..."
mkdir -p Plans/Dispatch 'Plans/In Progress' Plans/Resolved Handoffs 'Open Items/Closed'

if [ ! -f "Open Items.md" ]; then
cat << 'INNER_EOF' > "Open Items.md"
# Open Items

Single source of truth for open work across the project.

---

## Active

### General
| # | Title | Status | Priority | Latest note | Detail | Last touched | ID |
|---|-------|--------|----------|--------------|--------|---------------|-----|

---

## Resolved (archive)
| Title | Latest note | Detail | Resolved | ID |
|-------|--------------|--------|----------|-----|
INNER_EOF
fi

echo "⚙️ Running initialization..."
bash .agentflow/bin/init.sh

echo "🔄 Injecting local project context..."
PROJECT_NAME=$(basename "$PWD")
sed -i.bak "s/- \*\*Project:\*\* Graspp/- \*\*Project:\*\* $PROJECT_NAME/" .agents/rules/shared-truth.md || true
rm -f .agents/rules/shared-truth.md.bak

echo "✅ AgentFlow System Unpacked Successfully!"
echo "🚀 Boot the team with: ./.agentflow/bin/mornin.sh team"
exit 0

__PAYLOAD_BELOW__

